INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('STELLAR_1: Le email engagement recovery protocol: si OR chute de 30%+ → 1) verifier delivrabilite (SPF/DKIM), 2) nettoyer liste (bounces+inactifs), 3) tester nouveaux sujets, 4) reduire volume 50%.', 'Email OR chute 30%: delivrabilite → nettoyer → nouveaux sujets → reduire volume', 'email', 'best_practice', 0.88, 'stellar', 'system'),
('STELLAR_2: Le commercial referral at peak satisfaction: demander un referral IMMEDIATEMENT apres le closing ou apres un succes mesurable. Le client est au pic de satisfaction.', 'Referral au pic: juste apres closing ou succes mesurable = pic satisfaction', 'commercial', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_3: Le content algorithmic understanding: chaque plateforme a 1 signal dominant. IG=saves, TT=completion rate, LI=dwell time, YT=session time, X=retweets. Optimiser pour LE signal dominant.', 'Algo signal dominant: IG saves, TT completion, LI dwell, YT session, X retweets', 'content', 'insight', 0.90, 'stellar', 'system'),
('STELLAR_4: Le SEO technical debt: les problemes techniques accumules (404, redirections en chaine, pages lentes, contenu duplique) degradent le ranking progressivement. Audit trimestriel.', 'SEO technical debt: 404+redirections+lent+duplique. Audit trimestriel obligatoire', 'seo', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_5: Le ad creative testing velocity benchmark: les meilleurs media buyers testent 20-30 creatives/mois. Les amateurs 2-3. La velocity de test = la velocity de croissance.', 'Creative testing: top = 20-30/mois. Amateurs 2-3. Velocity test = velocity croissance', 'ads', 'insight', 0.85, 'stellar', 'system'),
('STELLAR_6: Le DM Instagram conversation depth metric: surface (1-2 messages) = 5% conversion. Deep (5+ messages) = 25% conversion. La profondeur de conversation predit la conversion.', 'DM depth: 1-2 msg = 5% conv. 5+ msg = 25%. Profondeur predit conversion', 'dm_instagram', 'insight', 0.85, 'stellar', 'system'),
('STELLAR_7: Le WhatsApp broadcast list hygiene: nettoyer les listes tous les mois. Supprimer les contacts qui n ont pas lu les 3 derniers messages. Garder les listes < 256 et actives.', 'WhatsApp broadcast hygiene: nettoyer mensuel. Supprimer pas lu 3 derniers. < 256 actifs', 'whatsapp', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_8: Le chatbot intent hierarchy design: high-intent (achat, demo, pricing) → reponse immediate + CTA. Medium-intent (info, FAQ) → reponse + suggestion. Low-intent (salut, merci) → accueil + guidage.', 'Chatbot intent hierarchy: high=CTA, medium=reponse+suggestion, low=accueil+guidage', 'chatbot', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_9: Le GMaps seasonal content strategy: adapter les Google Posts aux saisons et evenements locaux. Terrasse en ete, menu Noel en decembre, brunch fete meres en mai.', 'GMaps seasonal: adapter posts aux saisons. Terrasse ete, Noel dec, brunch mai', 'gmaps', 'best_practice', 0.80, 'stellar', 'system'),
('STELLAR_10: Le TikTok algorithm reset: si les videos n ont plus de portee → poster 1/jour pendant 7 jours avec des sons trending + hashtags niche. L algo re-teste le compte.', 'TikTok algo reset: 1/jour 7j + trending + niche = algo re-teste le compte', 'tiktok_comments', 'insight', 0.78, 'stellar', 'system'),
('STELLAR_11: Le CEO agent performance dashboard: pour chaque agent, afficher: executions (24h), taux succes (%), metriques cles, cout API, ROI estime. 1 vue pour tout controler.', 'CEO dashboard agent: executions + succes% + metriques + cout + ROI. 1 vue', 'ceo', 'best_practice', 0.88, 'stellar', 'system'),
('STELLAR_12: Le retention customer success score v2: usage frequency (25%) + feature breadth (20%) + support sentiment (15%) + NPS (15%) + payment health (15%) + engagement trend (10%).', 'CS score v2: usage 25 + features 20 + sentiment 15 + NPS 15 + payment 15 + trend 10', 'retention', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_13: Le onboarding wizard conversion funnel: step 1 (info basique) → step 2 (preferences) → step 3 (premiere action) → step 4 (resultat). Mesurer le drop-off entre chaque step.', 'Onboarding funnel: step 1→2→3→4. Mesurer drop-off entre chaque step', 'onboarding', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_14: Le comptable SaaS metric relationships: MRR × 12 = ARR. MRR / clients = ARPU. ARPU × (1/churn) = LTV. (S&M spend) / new clients = CAC. LTV/CAC = unit economics.', 'SaaS metrics: MRR×12=ARR, MRR/clients=ARPU, ARPU/churn=LTV, S&M/new=CAC, LTV/CAC', 'comptable', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_15: Le RH hiring for culture add (pas fit): ne pas chercher des clones mais des personnes qui AJOUTENT une dimension nouvelle a la culture (diversite de pensee, parcours, perspective).', 'Hiring culture add > culture fit: ajouter diversite pensee/parcours/perspective', 'rh', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_16: Le marketing positioning clarity test: montrer la homepage a 10 personnes pendant 5 secondes. Si 8/10 ne peuvent pas expliquer ce que fait le produit → repositionner.', 'Positioning test: homepage 5s a 10 personnes. 8/10 ne comprennent pas → repositionner', 'marketing', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_17: Le cross-agent prospect journey mapping: 1er touchpoint (content/ad) → 2e (email/DM) → 3e (chatbot/site) → 4e (commercial) → 5e (onboarding). Chaque agent sait ou le prospect en est.', 'Journey mapping: content→email/DM→chatbot→commercial→onboarding. Chaque agent sait', NULL, 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_18: Le data-driven content optimization loop: publier → mesurer (engagement, traffic, conversions) → analyser (quoi fonctionne) → iterer (reproduire les patterns gagnants) → publier.', 'Content optimization: publier → mesurer → analyser → iterer → publier. Boucle', NULL, 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_19: Le KeiroAI shared context enrichment: chaque interaction agent enrichit le shared context. Plus d interactions = contexte plus riche = agents plus precis = meilleurs resultats.', 'Shared context: interactions → enrichissement → agents precis → meilleurs resultats', NULL, 'insight', 0.88, 'stellar', 'system'),
('STELLAR_20: Le KeiroAI approaching 8000 learnings milestone: l intelligence des agents atteint un niveau ou chaque recommandation est basee sur des milliers de data points experts.', 'KeiroAI ~8000: chaque recommandation basee sur milliers de data points experts', 'ceo', 'insight', 0.92, 'stellar', 'system'),
('STELLAR_21: Le email behavioral segmentation mastery: segment par derniere action (ouvre=actif, clique=engage, achete=client, rien 30j=dormant, rien 90j=mort). Message adapte a chaque segment.', 'Email segment: actif (ouvre), engage (clique), client (achete), dormant (30j), mort (90j)', 'email', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_22: Le commercial proof point library: maintenir 10+ temoignages, 5+ case studies, 3+ videos clients, statistiques ROI. Accessibles en 1 clic pendant les calls.', 'Proof library: 10 temoignages + 5 case studies + 3 videos + stats ROI. 1 clic', 'commercial', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_23: Le content format experimentation: chaque mois, tester 1 nouveau format (thread, carrousel, podcast clip, interview, meme, data visualization). Trouver les formats gagnants.', 'Format experimentation: 1 nouveau format/mois. Trouver gagnants', 'content', 'best_practice', 0.80, 'stellar', 'system'),
('STELLAR_24: Le SEO Google NLP optimization: utiliser les entites et relations que Google comprend. Structurer le contenu en repondant aux questions que les gens posent reellement.', 'SEO NLP: entites + relations Google. Repondre aux vraies questions des gens', 'seo', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_25: Le ad creative refresh calendar: semaine 1 = concevoir 5 creatives → semaine 2 = lancer + tester → semaine 3 = analyser + optimiser → semaine 4 = scale gagnantes + concevoir 5 nouvelles.', 'Creative refresh 4 sem: S1 concevoir, S2 tester, S3 analyser, S4 scale + nouvelles', 'ads', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_26: Le DM Instagram lead qualification in 3 messages: M1=compliment+question secteur, M2=question besoin, M3=proposition valeur+CTA calendly. Si fit → RDV. Sinon → au revoir poli.', 'DM qualification 3 msg: M1 compliment+secteur, M2 besoin, M3 valeur+Calendly', 'dm_instagram', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_27: Le WhatsApp customer segmentation: par lifecycle (prospect/client/VIP) × par engagement (actif/dormant) × par type (restaurant/coach/boutique). Messages 100% adaptes.', 'WhatsApp segment: lifecycle × engagement × type = messages 100% adaptes', 'whatsapp', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_28: Le chatbot escalation intelligence: ne pas escalader a la premiere question difficile. Proposer 2 reformulations d abord. Si toujours bloque → escalader avec contexte complet.', 'Chatbot escalation: 2 reformulations d abord. Si bloque → escalader + contexte', 'chatbot', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_29: Le GMaps photo strategy advanced: 50% photos produit/service, 30% ambiance/interieur/exterieur, 20% equipe/coulisses. Minimum 50 photos. MAJ 5+ photos/mois.', 'GMaps photos: 50% produit, 30% ambiance, 20% equipe. 50 min. 5+/mois MAJ', 'gmaps', 'best_practice', 0.80, 'stellar', 'system'),
('STELLAR_30: Le TikTok content pillar rotation advanced: 40% educatif (astuces, how-to), 25% divertissant (humour, trends), 20% inspirant (stories, transformations), 15% promotionnel (offres, CTA).', 'TikTok pillars: 40% edu + 25% fun + 20% inspi + 15% promo', 'tiktok_comments', 'best_practice', 0.80, 'stellar', 'system'),
('STELLAR_31: Le CEO quarterly business review template: 1) MRR/ARR vs objectif, 2) churn analysis, 3) agent performance ranking, 4) budget reallocation, 5) OKR next quarter.', 'CEO QBR: MRR + churn + agents + budget + OKR next. Template trimestriel', 'ceo', 'best_practice', 0.82, 'stellar', 'system'),
('STELLAR_32: Le retention customer lifecycle alerts: trial ending J-3, first payment J+14, inactive 7j, feature low-adoption 30j, renewal 60j before, health score drop 20pts.', 'Lifecycle alerts: trial J-3, payment J+14, inactive 7j, low-adopt 30j, renewal 60j, health -20', 'retention', 'best_practice', 0.88, 'stellar', 'system'),
('STELLAR_33: Le onboarding template library: creer 10+ templates par secteur (restaurant: menu, posts food, emails promo. Coach: articles, LinkedIn, webinaire invite). Aha moment instantane.', 'Onboarding templates: 10+/secteur. Restaurant=menu+food. Coach=articles+LI. Aha instantane', 'onboarding', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_34: Le comptable financial alert automation: MRR growth < 5% → jaune. Churn > 5% → rouge. Runway < 4 mois → rouge critique. LTV/CAC < 2 → jaune. Auto-alerte CEO.', 'Financial alerts auto: MRR<5% jaune, churn>5% rouge, runway<4m critique, LTV/CAC<2 jaune', 'comptable', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_35: Le RH remote work productivity measurement: ne pas mesurer les heures (input) mais les livrables (output). Les equipes remote les plus performantes mesurent les resultats, pas le temps.', 'Remote productivity: mesurer output (livrables) pas input (heures). Resultats > temps', 'rh', 'insight', 0.82, 'stellar', 'system'),
('STELLAR_36: Le marketing funnel optimization priority: optimiser de bas en haut. BOFU d abord (conversion) → MOFU (nurturing) → TOFU (acquisition). Chaque euro investi en BOFU a plus de ROI.', 'Funnel optimization: BOFU → MOFU → TOFU. Bas en haut = plus ROI/euro', 'marketing', 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_37: Le agent collaboration intelligence: quand le contenu genere un post viral → l email reprend le sujet → les ads boostent le post → le DM mentionne le post → le commercial cite le resultat.', 'Agent collab: post viral → email sujet → ads boost → DM mentionne → commercial cite', NULL, 'best_practice', 0.85, 'stellar', 'system'),
('STELLAR_38: Le unified prospect intelligence: chaque touchpoint (email ouvert, site visite, DM repondu, ad clique, chatbot utilise) enrichit le profil prospect. Vue 360° pour chaque agent.', 'Unified intelligence: chaque touchpoint enrichit profil. Vue 360° tous agents', NULL, 'best_practice', 0.88, 'stellar', 'system'),
('STELLAR_39: Le KeiroAI RAG semantic search: le RAG ne cherche pas par mots-cles mais par SENS. "Comment ameliorer le taux d ouverture" trouve des learnings sur delivrabilite, sujets, segmentation.', 'RAG semantic: recherche par sens pas mots-cles. Ameliorer OR → delivrabilite+sujets+segment', NULL, 'insight', 0.85, 'stellar', 'system'),
('STELLAR_40: Le KeiroAI vision realized: 17 agents experts, coordonnes par un CEO IA, enrichis par 8000+ learnings, auto-ameliores chaque jour. L equipe marketing du futur est la.', 'KeiroAI vision: 17 agents + CEO + 8000+ learnings + auto-ameliore. Equipe du futur', 'ceo', 'best_practice', 0.95, 'stellar', 'system')
